      out.write("function closeAll(){closeSettings();closeProfile();closeChangePassword();}\n");
      out.write("function submitPassword() {\n");
      out.write("    const newPassword = document.getElementById(\"newPassword\").value.trim();\n");
      out.write("    const confirmPassword = document.getElementById(\"confirmPassword\").value.trim();\n");
      out.write("\n");
      out.write("    if (!newPassword || !confirmPassword) {\n");
      out.write("        showToast(\"Please fill all fields\");\n");
      out.write("        return;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    fetch(\"");
      out.print(request.getContextPath());
      out.write("/changePassword\", {\n");
      out.write("        method: \"POST\",\n");
      out.write("        headers: {\n");
      out.write("            \"Content-Type\": \"application/x-www-form-urlencoded\"\n");
      out.write("        },\n");
      out.write("        body: new URLSearchParams({\n");
      out.write("            newPassword: newPassword,\n");
      out.write("            confirmPassword: confirmPassword\n");
      out.write("        })\n");
      out.write("    })\n");
      out.write("    .then(res => res.text())\n");
      out.write("    .then(data => {\n");
