      out.write("        } \n");
      out.write("        else if (data === \"MissingFields\") {\n");
      out.write("        	showToast(\"Please fill all fields\", \"warning\");\n");
      out.write("        } \n");
      out.write("        else {\n");
      out.write("            showToast(\"Password must be at least 8 characters with uppercase, lowercase, number, and symbol.\");\n");
      out.write("        }\n");
      out.write("    })\n");
      out.write("    .catch(err => {\n");
      out.write("        console.error(err);\n");
      out.write("        showToast(\"Server error\");\n");
      out.write("    });\n");
      out.write("}\n");
